import outlines
from outlines.prompts import register_filter, unregister_filter

register_filter('shout', str.upper)

@outlines.prompt
def greet(text):
    '{{ text | shout }}'

print(greet('hello'))

# local/base filters take precedence over a same-named global filter
register_filter('name', lambda x: 'HIJACKED')

@outlines.prompt
def show_name(fn):
    '{{ fn | name }}'

def my_func():
    pass

print(show_name(my_func))  # should print 'my_func', not 'HIJACKED'

unregister_filter('shout')
try:
    print(greet('hello again'))
    print('ERROR: should have raised')
except Exception as e:
    print('OK, unregister works:', type(e).__name__)
"

