import outlines
from outlines.prompts import register_filter, unregister_filter

register_filter('shout', str.upper)

@outlines.prompt
def greet(text):
    '{{ text | shout }}'
print('global filter:', greet('hello'))

@outlines.prompt(filters={'shout': lambda s: s + '!!!'})
def greet2(text):
    '{{ text | shout }}'
print('local overrides global:', greet2('hello'))

register_filter('name', lambda x: 'HIJACKED')
@outlines.prompt
def show_name(fn):
    '{{ fn | name }}'
def my_func(): pass
print('builtin beats global:', show_name(my_func))

unregister_filter('shout')
try:
    print(greet('hello again'))
    print('ERROR: should have raised')
except Exception as e:
    print('unregister works:', type(e).__name__)
"
